<?php namespace App\Domains\BeautyShop\Services; class BeautyProductService { public function create(array $data) { return \App\Domains\BeautyShop\Models\BeautyProduct::create($data); } public function update($id, array $data) { $product = \App\Domains\BeautyShop\Models\BeautyProduct::find($id); return $product ? $product->update($data) : false; } public function delete($id) { return \App\Domains\BeautyShop\Models\BeautyProduct::destroy($id); } public function list($tenantId) { return \App\Domains\BeautyShop\Models\BeautyProduct::where('tenant_id', $tenantId)->get(); } }
